import PySimpleGUI as sg
from tkinterdnd2 import DND_FILES, TkinterDnD
import re
import sys
import os
import json
import shutil
import subprocess

VISION = "1.0.0"
UPDATE_DATE = "2026-04-01"
COFFEE_QR_BASE64 = ""
file_list = []  # 全局文件列表变量

# 解析拖放数据，支持多种格式
def parse_dropped_files(data):
    data = data.strip()
    if not data:
        return []
    if '{' in data and '}' in data:
        return re.findall(r'{([^{}]*)}', data)
    if '\n' in data:
        return [p for p in data.split('\n') if p.strip()]
    if ' ' in data:
        parts = data.split(' ')
        return [p for p in parts if p.strip()]
    return [data]

# 更新列表框显示
def update_listbox(window, file_list):
    """同步更新列表框显示"""
    window["-FILE_LIST-"].update(values=file_list)
    print(f"更新列表框: {file_list}")

# 拖放事件处理函数
def on_drop(event, window):
    global file_list
    raw_data = event.data
    print("\n=== 拖放事件 ===")
    print("原始数据:", repr(raw_data))
    new_paths = parse_dropped_files(raw_data)
    print("新拖入的路径:", new_paths)
    # 去重添加
    added = 0
    for p in new_paths:
        if p not in file_list:
            file_list.append(p)
            added += 1
    print(f"添加了 {added} 个新文件")
    print(f"当前文件列表: {file_list}")
    update_listbox(window, file_list)
    print("===============\n")

# 清空文件夹内容
def clear_folder(folder_path):
    """清空指定文件夹内的所有内容，但保留文件夹本身"""
    if not os.path.exists(folder_path):
        os.makedirs(folder_path)  # 如果不存在则创建
        return
    # 删除整个文件夹
    shutil.rmtree(folder_path)
    # 重新创建空文件夹
    os.makedirs(folder_path)

# ---------- 新增：扫描插件，返回按钮列表（每个按钮是一个字典） ----------
def scan_plugins(plugins_dir="plugins"):
    """返回按钮列表，每个元素包含：
       category, label, tooltip, executable_path, type, key, plugin_folder
    """
    all_buttons = []
    if not os.path.exists(plugins_dir):
        return all_buttons
    for folder in os.listdir(plugins_dir):
        folder_path = os.path.join(plugins_dir, folder)
        if not os.path.isdir(folder_path):
            continue
        json_path = os.path.join(folder_path, "manifest.json")
        if not os.path.exists(json_path):
            continue
        with open(json_path, "r", encoding="utf-8") as f:
            info = json.load(f)
        category = info.get("category", "未分类")
        
        # 情况1：新版多按钮格式（存在 "buttons" 字段）
        if "buttons" in info:
            for btn in info["buttons"]:
                label = btn.get("label")
                exe = btn.get("executable")
                if not label or not exe:
                    continue
                exe_path = os.path.join(folder_path, exe)
                if not os.path.exists(exe_path):
                    print(f"警告：按钮 {label} 的可执行文件不存在 {exe_path}")
                    continue
                btn_type = btn.get("type")
                if not btn_type:
                    # 根据扩展名自动判断
                    if exe.endswith(".py"):
                        btn_type = "script"
                    elif exe.endswith(".json"):
                        btn_type = "config"
                    else:
                        btn_type = "script"
                # 生成唯一 key（使用插件文件夹名 + 按钮标签，避免重复）
                key = f"BTN_{folder}_{label}"
                all_buttons.append({
                    "category": category,
                    "label": label,
                    "tooltip": btn.get("tooltip", label),
                    "executable_path": exe_path,
                    "type": btn_type,
                    "key": key,
                    "plugin_folder": folder_path   # 备用，config 类型可能需要
                })
        else:
            # 情况2：旧版单按钮格式（只有 name, executable）
            name = info.get("name", folder)
            exe = info.get("executable")
            if not exe:
                continue
            exe_path = os.path.join(folder_path, exe)
            if not os.path.exists(exe_path):
                print(f"警告：插件 {name} 的可执行文件不存在 {exe_path}")
                continue
            key = f"BTN_{folder}_{name}"   # 兼容旧 key
            all_buttons.append({
                "category": category,
                "label": name,
                "tooltip": info.get("description", name),
                "executable_path": exe_path,
                "type": "script",   # 旧版只可能是脚本
                "key": key,
                "plugin_folder": folder_path
            })
    return all_buttons

# 动态构建 layout（基于按钮列表）
def build_layout(buttons):
    # 固定部分（文件列表区域）
    layout = [
        [  # 第一行：两个 Column 并排
            sg.Column([
                [sg.Text("拖入文件，可以选中一个或多个移除 (请不要拖入同名文件)")],
                [sg.Listbox(values=[], size=(60, 17), key="-FILE_LIST-", select_mode=sg.SELECT_MODE_EXTENDED)]
            ]),
            sg.Column([
                [sg.Text("日志", justification='left')],
                [sg.Multiline(size=(20, 17), key="-LOG-", autoscroll=True, disabled=True, write_only=False, reroute_stdout=True)]
            ])
        ],
        [  # 第二行：按钮
            sg.Button("清空所有"),
            sg.Button("移除选中")
        ],
    ]
    
    # 按 (category, plugin_folder) 分组
    from collections import defaultdict
    groups = defaultdict(list)      # key: (category, plugin_folder), value: list of buttons
    for btn in buttons:
        # 从 key 中提取 plugin_folder：key 格式为 "BTN_{folder}_{label}"
        # 或者可以在 scan_plugins 时直接添加 'plugin_folder' 字段（已有）
        folder = btn.get('plugin_folder', 'unknown')
        groups[(btn['category'], folder)].append(btn)
    
    # 记录上一个类别，用于判断是否需要添加类别标题
    last_category = None
    for (category, folder), btns in groups.items():
        # 如果类别变化，添加类别标题行
        if category != last_category:
            layout.append([sg.Text(category, font=("微软雅黑", 10, "bold"))])
            last_category = category
        # 为该插件的所有按钮生成一行（水平排列）
        row = []
        for btn in btns:
            row.append(sg.Button(btn["label"], key=btn["key"], tooltip=btn["tooltip"], size=(20, 1)))
        layout.append(row)
    
    # 底部导出按钮和版权信息
    layout.extend([
        [sg.Push(), sg.Text("处理完成请点击导出按钮创建文件")],
        [sg.Push(), sg.Button("导出", key="output_file", size=(5, 1)), sg.Button("导出并打开位置", key="output_file_and_open", size=(15, 1))]
    ])
    layout.extend([
        [sg.HorizontalSeparator()], [sg.Text(f"视频后期工具箱 - {VISION} ({UPDATE_DATE})"), sg.Push(), sg.Button("关于", key="about", size=(5, 1))]
        ])
    
    return layout

# 把文件列表发送给插件执行（script 类型专用）
def run_script_plugin(plugin_path, window):
    global file_list

    # 获取程序根目录
    if getattr(sys, 'frozen', False):
        program_dir = os.path.dirname(sys.executable)
    else:
        program_dir = os.path.dirname(os.path.abspath(__file__))

    cache_dir = os.path.join(program_dir, "cache/output")
    os.makedirs(cache_dir, exist_ok=True)

    forward_json = {
        "output_path": cache_dir,
        "pending_file_lists": file_list
    }
    json_str = json.dumps(forward_json, ensure_ascii=False)

    # 关键修改：根据环境和文件类型决定调用方式
    if not getattr(sys, 'frozen', False) and plugin_path.endswith('.py'):
        # 开发环境且插件是 .py 脚本 → 用 Python 解释器运行
        cmd = [sys.executable, plugin_path]
    else:
        # 打包后，插件应为独立 exe，直接运行
        cmd = [plugin_path]

    proc = subprocess.Popen(
        cmd,
        stdin=subprocess.PIPE,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        encoding='utf-8'
    )
    stdout, stderr = proc.communicate(json_str)

    if proc.returncode == 0:
        print("插件处理成功")
        if stdout:
            try:
                message = json.loads(stdout)
                if message.get("popup"):
                    sg.popup(message["popup"]["message"], title=message["popup"]["title"])
                if message.get("completed_output_lists"):
                    file_list = message["completed_output_lists"]
                    update_listbox(window, file_list)
            except json.JSONDecodeError:
                print("插件返回的数据不是有效的 JSON 格式")
                print("插件输出:", stdout)
    else:
        print(f"插件出错，退出码 {proc.returncode}")
        if stderr:
            print(stderr)
# 将 src_dir 中的所有文件移动到 dst_dir（不处理子文件夹）
def move_all_files(src_dir, dst_dir):
    os.makedirs(dst_dir, exist_ok=True)
    for filename in os.listdir(src_dir):
        src_path = os.path.join(src_dir, filename)
        if os.path.isfile(src_path):
            dst_path = os.path.join(dst_dir, filename)
            if os.path.exists(dst_path):
                base, ext = os.path.splitext(filename)
                counter = 1
                while os.path.exists(os.path.join(dst_dir, f"{base}_{counter}{ext}")):
                    counter += 1
                dst_path = os.path.join(dst_dir, f"{base}_{counter}{ext}")
            shutil.move(src_path, dst_path)

# 显示关于窗口
def show_about_window():
    layout = [
        [  # 第一行：两个 Column 并排
            sg.Column([
                [sg.Text("请作者喝咖啡", font=("微软雅黑", 12, "bold"))],
                [sg.Image(data=COFFEE_QR_BASE64, size=(300, 300))]
            ])
        ],
        [sg.Text("欢迎联系作者", font=("微软雅黑", 12, "bold"))],
        [sg.Text("B站: Re世界第一可爱")],
        [sg.Text("Q群: 529148372")],
        [sg.Text("GitHub: github.com/100210110")],
        [sg.Button("关闭", size=(10, 1))]
    ]
    window = sg.Window("联系作者", layout, modal=True, finalize=True, keep_on_top=True)
    while True:
        event, _ = window.read()
        if event in (sg.WIN_CLOSED, "关闭"):
            break
    window.close()

# 主程序
def main():
    # 获取程序根目录
    if getattr(sys, 'frozen', False):
        program_dir = os.path.dirname(sys.executable)
    else:
        program_dir = os.path.dirname(os.path.abspath(__file__))

    # 清空缓存目录
    clear_dir = os.path.join(program_dir, "cache/output")
    clear_folder(clear_dir)

    # 扫描插件（新版多按钮支持）
    buttons = scan_plugins()
    if not buttons:
        sg.popup_error("未找到任何插件，请检查 plugins 文件夹")
        return

    # 创建带拖拽支持的根窗口
    root = TkinterDnD.Tk()
    root.withdraw()

    layout = build_layout(buttons)
    window = sg.Window("Re工具箱", layout, finalize=True)

    # 注册拖拽事件
    listbox_widget = window["-FILE_LIST-"].Widget
    listbox_widget.drop_target_register(DND_FILES)
    listbox_widget.dnd_bind('<<Drop>>', lambda e: on_drop(e, window))

    # 处理命令行参数（拖拽到exe）
    if len(sys.argv) > 1:
        print("从命令行参数添加文件:")
        for file_path in sys.argv[1:]:
            file_list.append(file_path)
            print(f"添加: {file_path}")
        update_listbox(window, file_list)

    def refresh_listbox():
        update_listbox(window, file_list)

    # 为了方便事件处理，构建一个从 key 到按钮字典的映射
    button_map = {btn["key"]: btn for btn in buttons}

    # 事件循环
    while True:
        event, values = window.read()
        if event == sg.WIN_CLOSED:
            break

        # 固定按钮
        if event == "清空所有":
            file_list.clear()
            update_listbox(window, file_list)
            print("\n手动清空所有文件\n")

        elif event == "移除选中":
            print("\n=== 移除选中事件 ===")
            print("当前文件列表:", file_list)
            selected_values = values["-FILE_LIST-"]
            print("选中的值:", selected_values)
            if not selected_values:
                sg.popup("请先选中要移除的项目")
            else:
                original_len = len(file_list)
                for item in selected_values:
                    if item in file_list:
                        file_list.remove(item)
                print(f"删除了 {original_len - len(file_list)} 个文件")
                print(f"剩余文件列表: {file_list}")
                update_listbox(window, file_list)
            print("=================")

        # 处理动态按钮（插件或配置）
        elif event in button_map:
            btn_info = button_map[event]
            if btn_info["type"] == "script":
                print(f"\n=== 启动脚本插件：{btn_info['label']} ===")
                run_script_plugin(btn_info["executable_path"], window)
                print("=================")
            elif btn_info["type"] == "config":
                print(f"\n=== 打开配置文件：{btn_info['executable_path']} ===")
                # 用记事本打开配置文件
                subprocess.run(['notepad.exe', btn_info["executable_path"]])
                print("=================")
            else:
                print(f"未知按钮类型：{btn_info['type']}")

        elif event == "output_file":
            move_all_files(clear_dir, os.path.join(program_dir, "output"))
            file_list.clear()
            update_listbox(window, file_list)

        elif event == "output_file_and_open":
            move_all_files(clear_dir, os.path.join(program_dir, "output"))
            subprocess.run(f'explorer "{os.path.join(program_dir, "output")}"', shell=True)
            file_list.clear()
            update_listbox(window, file_list)

        elif event == "about":
            show_about_window()

    window.close()

if __name__ == "__main__":
    main()